#include <stdio.h>
int main(){
    int T; if(scanf("%d", &T)!=1) return 0;
    while(T--){
        int X; scanf("%d", &X);
        int dLeft = X - 1;
        int dRight = 100 - X;
        if(dLeft <= dRight) printf("LEFT\n");
        else printf("RIGHT\n");
    }
    return 0;
}

